/**
 * CombatLog — Singleton that subscribes to CombatSystem events and appends
 * formatted entries to the #combat-log-entries DOM element.
 *
 * - Subscribes to all combat:* events via CombatSystem.subscribe()
 * - Formats messages from event data into human-readable strings
 * - Caps the log at 100 visible entries (removes oldest)
 * - Auto-scrolls to the latest entry
 * - The container (#combat-log) is collapsible via clicking the header
 *
 * @module CombatLog
 */

import DebugLog from '../debug/DebugLog.js';
import CombatSystem from '../systems/CombatSystem.js';

// ─── CombatLog ───────────────────────────────────────────────────────────────

const CombatLog = {
  /** @type {Function|null} CombatSystem unsubscribe handle */
  _unsubscribe: null,

  /** @type {HTMLElement|null} The scrollable entries container */
  _entriesEl: null,

  /** @type {number} Current visible entry count */
  _entryCount: 0,

  /** @type {number} Max visible entries before pruning oldest */
  MAX_ENTRIES: 100,

  /**
   * Initialise the CombatLog: wire up event subscriptions and DOM references.
   * Safe to call multiple times — will not double-subscribe.
   */
  init() {
    // Unsubscribe any previous subscription
    this._unsubscribe?.();
    this._unsubscribe = null;

    // Resolve DOM element
    this._entriesEl = document.getElementById('combat-log-entries');
    this._entryCount = 0;

    // Subscribe to CombatSystem events
    this._unsubscribe = CombatSystem.subscribe((type, data) => {
      this._onCombatEvent(type, data);
    });

    // Wire collapsible header
    const titleEl = document.getElementById('combat-log-title');
    const logEl   = document.getElementById('combat-log');
    if (titleEl && logEl) {
      titleEl.style.cursor = 'pointer';
      titleEl.title = 'Click to collapse/expand';
      titleEl.addEventListener('click', () => {
        logEl.classList.toggle('collapsed');
      });
    }

    DebugLog.info('[combat] CombatLog initialised');
  },

  /**
   * Tear down event subscription. Called when CombatScene is destroyed.
   */
  destroy() {
    this._unsubscribe?.();
    this._unsubscribe = null;
    this._entriesEl = null;
    this._entryCount = 0;
  },

  // ── Event handler ──────────────────────────────────────────────────────────

  /**
   * Handle incoming combat events and convert them to log messages.
   * @param {string} type
   * @param {object} data
   */
  _onCombatEvent(type, data) {
    let message = null;
    let category = 'default';

    switch (type) {
      case 'combat:start':
        message = 'Combat begins!';
        category = 'system';
        break;

      case 'combat:turn_start': {
        const state = CombatSystem.getState?.();
        if (state?.combatants) {
          const c = state.combatants instanceof Map
            ? state.combatants.get(data.combatantId)
            : state.combatants[data.combatantId];
          if (c) {
            message = `${c.name}'s turn`;
            category = c.isPlayer ? 'default' : 'default';
          }
        }
        break;
      }

      case 'combat:new_round':
        message = `\u2014 Round ${data.round} \u2014`;
        category = 'system';
        break;

      case 'combat:log':
        // CombatSystem already formats messages and emits them as combat:log
        message = data.message;
        category = data.category ?? 'default';
        break;

      case 'combat:attack': {
        const result = data.result ?? {};
        const state  = CombatSystem.getState?.();
        let attackerName = data.attackerId;
        let targetName   = data.targetId;
        if (state?.combatants) {
          const map = state.combatants;
          const get = (id) => map instanceof Map ? map.get(id) : map[id];
          attackerName = get(data.attackerId)?.name ?? data.attackerId;
          targetName   = get(data.targetId)?.name   ?? data.targetId;
        }
        if (result.outcome === 'miss') {
          message = `${attackerName} attacks ${targetName} \u2014 MISS`;
          category = 'miss';
        } else if (result.outcome === 'crit') {
          message = `${attackerName} attacks ${targetName} \u2014 CRITICAL! ${result.damage} dmg`;
          category = 'crit';
        } else {
          message = `${attackerName} attacks ${targetName} for ${result.damage} damage`;
          category = 'attack';
        }
        break;
      }

      case 'combat:skill': {
        const state = CombatSystem.getState?.();
        let casterName = data.casterId;
        if (state?.combatants) {
          const map = state.combatants;
          casterName = (map instanceof Map ? map.get(data.casterId) : map[data.casterId])?.name ?? data.casterId;
        }
        // Summarise skill events
        const dmgEvents   = (data.events ?? []).filter(e => e.type === 'damage');
        const healEvents  = (data.events ?? []).filter(e => e.type === 'heal');
        const statusEvs   = (data.events ?? []).filter(e => e.type === 'status');
        if (dmgEvents.length > 0) {
          const total = dmgEvents.reduce((s, e) => s + (e.amount ?? 0), 0);
          const hasCrit = dmgEvents.some(e => e.isCrit);
          message = hasCrit
            ? `${casterName} uses ${data.skillId} \u2014 CRITICAL! ${total} dmg`
            : `${casterName} uses ${data.skillId} for ${total} damage`;
          category = hasCrit ? 'crit' : 'skill';
        } else if (healEvents.length > 0) {
          const total = healEvents.reduce((s, e) => s + (e.amount ?? 0), 0);
          message = `${casterName} uses ${data.skillId}, restoring ${total} HP`;
          category = 'heal';
        } else if (statusEvs.length > 0) {
          message = `${casterName} uses ${data.skillId} \u2014 ${statusEvs.map(e => e.statusId).join(', ')}`;
          category = 'status';
        } else {
          message = `${casterName} uses ${data.skillId}`;
          category = 'skill';
        }
        break;
      }

      case 'combat:hit': {
        // Emitted with explicit position data from M22 additions
        const state = CombatSystem.getState?.();
        let targetName = data.target?.name ?? data.targetId ?? 'target';
        if (!data.target?.name && state?.combatants) {
          const map = state.combatants;
          targetName = (map instanceof Map ? map.get(data.targetId) : map[data.targetId])?.name ?? targetName;
        }
        if (data.isCrit) {
          message = `Critical hit on ${targetName} for ${data.damage} dmg!`;
          category = 'crit';
        } else {
          message = `Hit ${targetName} for ${data.damage} dmg`;
          category = 'attack';
        }
        break;
      }

      case 'combat:miss': {
        const targetName = data.target?.name ?? data.targetId ?? 'target';
        message = `Missed ${targetName}`;
        category = 'miss';
        break;
      }

      case 'combat:heal': {
        const targetName = data.target?.name ?? data.targetId ?? 'target';
        message = `${targetName} restored ${data.amount} HP`;
        category = 'heal';
        break;
      }

      case 'combat:status': {
        const targetName = data.target?.name ?? data.targetId ?? 'target';
        message = `${targetName}: ${data.statusName ?? data.statusId ?? 'status applied'}`;
        category = 'status';
        break;
      }

      case 'combat:xp':
        message = `+${data.amount} XP`;
        category = 'xp';
        break;

      case 'combat:end':
        message = data.winner === 'party' ? 'Victory!' : 'Defeated...';
        category = 'system';
        break;

      default:
        // Ignore unhandled events silently
        return;
    }

    if (message) {
      this._append(message, category);
    }
  },

  // ── DOM append ─────────────────────────────────────────────────────────────

  /**
   * Append a message to the combat log DOM element.
   * Prunes oldest entries if count exceeds MAX_ENTRIES.
   * Auto-scrolls to the bottom.
   *
   * @param {string} message
   * @param {string} category
   */
  _append(message, category) {
    // Lazily re-acquire DOM reference if needed
    if (!this._entriesEl) {
      this._entriesEl = document.getElementById('combat-log-entries');
    }
    if (!this._entriesEl) return;

    const entry = document.createElement('div');
    const cls = this._categoryClass(category);
    entry.className = `log-entry ${cls}`;
    entry.textContent = message;

    this._entriesEl.appendChild(entry);
    this._entryCount++;

    // Prune oldest entries
    if (this._entryCount > this.MAX_ENTRIES) {
      const first = this._entriesEl.firstElementChild;
      if (first) {
        first.remove();
        this._entryCount--;
      }
    }

    // Auto-scroll to latest
    this._entriesEl.scrollTop = this._entriesEl.scrollHeight;
  },

  /**
   * Map a category string to a log CSS class.
   * @param {string} category
   * @returns {string}
   */
  _categoryClass(category) {
    switch (category) {
      case 'attack':  return 'log-cat-attack';
      case 'miss':    return 'log-cat-miss';
      case 'crit':    return 'log-cat-crit';
      case 'status':  return 'log-cat-status';
      case 'death':   return 'log-cat-death';
      case 'system':  return 'log-cat-system';
      case 'combo':   return 'log-cat-combo';
      case 'skill':   return 'log-cat-skill';
      case 'heal':    return 'log-cat-heal';
      case 'xp':      return 'log-cat-system';
      default:        return 'log-cat-default';
    }
  },
};

export default CombatLog;
